class Solution(object):
    def minimumCost(self, nums):
        def is_palindrome(x):
            s = str(x)
            return s == s[::-1]

        def total_cost(target):
            return sum(abs(v - target) for v in nums)

        nums.sort()
        median = nums[len(nums) // 2]

        # Find nearest palindromes around median
        # Search downward
        lo = median
        while not is_palindrome(lo):
            lo -= 1
        # Search upward
        hi = median
        while not is_palindrome(hi):
            hi += 1

        return min(total_cost(lo), total_cost(hi))
